const manualOverride = global.get('manualOverride') || false;
const prevMode = global.get('operationMode') || 'unknown';
const prevServerOnline = global.get('serverOnline');

// 서버 응답 확인
let serverOnline = false;
if (msg.statusCode === 200 && msg.payload && (msg.payload.success === true || msg.payload.status === 'ok')) {
    serverOnline = true;
}

global.set('serverOnline', serverOnline);

// 모드 결정: 수동 스위치 ON → 강제 오프라인
const operationMode = manualOverride ? 'offline' : (serverOnline ? 'online' : 'offline');
global.set('operationMode', operationMode);

let syncMsg = null;
let configMsg = null;

// 상태 변경 감지
if (prevMode !== operationMode) {
    node.warn(`🔄 모드 변경: ${prevMode} → ${operationMode}`);

    // 온라인 전환 시 동기화 트리거 (unknown/offline → online 모두 포함)
    if (prevMode !== 'online' && operationMode === 'online') {
        node.warn('🔄 온라인 복귀! 데이터 동기화 시작...');
        syncMsg = { payload: 'sync_trigger' };
    }
}

// 서버 온라인 + config 미캐시 → config 가져오기 (API 키 포함)
if (serverOnline && !global.get('houseConfig')) {
    node.warn('📋 서버에서 config 캐시 가져오기...');
    const API_KEY = env.get('SENSOR_API_KEY') || '';
    configMsg = {
        payload: 'fetch_config',
        method: 'GET',
        headers: { 'x-api-key': API_KEY }
    };
}

// 상태 표시
const modeLabel = operationMode === 'online' ? '온라인' : '오프라인';
const manualLabel = manualOverride ? ' (수동)' : '';
const serverLabel = serverOnline ? '서버 정상' : '서버 다운';
const configLabel = global.get('houseConfig') ? ' | config ✓' : '';

node.status({
    fill: operationMode === 'online' ? 'green' : 'yellow',
    shape: manualOverride ? 'ring' : 'dot',
    text: `${modeLabel}${manualLabel} | ${serverLabel}${configLabel}`
});

msg.payload = {
    operationMode,
    serverOnline,
    manualOverride,
    timestamp: new Date().toISOString()
};

return [msg, syncMsg, configMsg];

// 다른 플로우에서 참조할 수 있도록 상태 요약 저장
global.set('systemStatus', {
    operationMode: msg.payload.operationMode,
    serverOnline: msg.payload.serverOnline,
    manualOverride: msg.payload.manualOverride,
    lastCheck: msg.payload.timestamp
});
return msg;

if (msg.statusCode === 200 && msg.payload && msg.payload.success && msg.payload.data) {
    const config = msg.payload.data;
    global.set('houseConfig', config);
    node.warn('📋 Config 캐시 완료: ' + (config.houses ? config.houses.length + '개 하우스' : '데이터 없음'));
    node.status({ fill: 'green', shape: 'dot', text: 'config 캐시 완료' });

    // SQLite config_cache에도 저장 (위치 파라미터 - msg.payload 배열)
    msg.topic = 'INSERT OR REPLACE INTO config_cache (id, farm_id, house_id, config_json, version, updated_at) VALUES (1, $1, $2, $3, $4, $5)';
    msg.payload = [
        config.farmId || 'farm_0001',
        config.houseId || (config.houses && config.houses[0] ? config.houses[0].houseId : 'house_001'),
        JSON.stringify(config),
        config.configVersion || 1,
        new Date().toISOString()
    ];
    return msg;
} else {
    node.warn('⚠️ Config 가져오기 실패: ' + JSON.stringify(msg.payload).substring(0, 100));
    node.status({ fill: 'red', shape: 'dot', text: 'config 실패' });
    return null;
}

const status = global.get('systemStatus') || {};
msg.payload = {
    success: true,
    data: {
        operationMode: global.get('operationMode') || 'online',
        serverOnline: global.get('serverOnline') || false,
        manualOverride: global.get('manualOverride') || false,
        lastCheck: status.lastCheck || null
    }
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

const { manual } = msg.payload;

if (typeof manual !== 'boolean') {
    msg.payload = { success: false, error: 'manual (boolean) 필수' };
    msg.statusCode = 400;
    return msg;
}

global.set('manualOverride', manual);

// 즉시 모드 재계산
const serverOnline = global.get('serverOnline') || false;
const operationMode = manual ? 'offline' : (serverOnline ? 'online' : 'offline');
global.set('operationMode', operationMode);

const modeLabel = operationMode === 'online' ? '온라인' : '오프라인';
const manualLabel = manual ? '수동' : '자동';

node.warn(`🔄 모드 전환: ${manualLabel} → ${modeLabel}`);
node.status({
    fill: manual ? 'yellow' : 'green',
    shape: 'dot',
    text: `${manualLabel} → ${modeLabel}`
});

msg.payload = {
    success: true,
    data: {
        operationMode,
        serverOnline,
        manualOverride: manual
    }
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, x-api-key'
};
msg.payload = '';
msg.statusCode = 204;
return msg;
